3433	\begin{lemma}\leanok
3434	[IsIso plumbing from the unit square]
3435	  \label{lem:isiso_sheafifyeta_of_unitsquare}
3436	  \lean{AlgebraicGeometry.Scheme.Modules.isIso_sheafifyEta_of_unitSquare}
3437	  \uses{lem:pullback_unit_iso}
3438	  Suppose the \emph{unit square}
3439	  \[
3440	    (\mathtt{pullbackValIso}\,f\,\mathcal{O}_X).\mathrm{inv} \;\mathbin{;}\;
3441	      a_Y.\mathrm{map}\,(\eta\,F) \;\mathbin{;}\;
3442	      \mathtt{sheafifyUnitIso}.\mathrm{hom}
3443	      \;=\; \mathtt{pullbackObjUnitToUnit}\,\varphi
3444	  \]
3445	  commutes. Then \(a_Y.\mathrm{map}\,(\eta\,F)\) is an isomorphism.
3446	\end{lemma}
3447	
3448	\begin{proof}
3449	  \uses{lem:pullback_unit_iso}
3450	  The right-hand side \(\mathtt{pullbackObjUnitToUnit}\,\varphi : f^*\mathcal{O}_X \to
3451	  \mathcal{O}_Y\) is an isomorphism for \emph{every} \(f\): it is \(\mathtt{pullbackUnitIso}\,f\)
3452	  (\cref{lem:pullback_unit_iso}), the iso-ness coming from the finality of
3453	  \(\mathtt{Opens.map}\,f.\mathrm{base}\). The morphisms \(\mathtt{pullbackValIso}\,f\,\mathcal{O}_X\)
3454	  and \(\mathtt{sheafifyUnitIso}\) are isomorphisms by construction. Solving the square for the
3455	  middle factor exhibits
3456	  \[
3457	    a_Y.\mathrm{map}\,(\eta\,F)
3458	      \;=\;
3459	      (\mathtt{pullbackValIso}\,f\,\mathcal{O}_X).\mathrm{hom} \;\mathbin{;}\;
3460	      \mathtt{pullbackObjUnitToUnit}\,\varphi \;\mathbin{;}\;
3461	      \mathtt{sheafifyUnitIso}.\mathrm{hom}^{-1},
3462	  \]
3463	  a composite of three isomorphisms, hence an isomorphism.
3464	\end{proof}
